// Find the handleSubmit function and replace with this:

const handleSubmit = async (e) => {
  e.preventDefault();

  if (step === 2 && !validateStep2()) {
    return;
  }

  if (step === 2) {
    setLoading(true);
    setError('');

    try {
      // Make sure ALL form data is included
      const completePatientData = {
        ...formData,
        // Ensure all fields are explicitly included
        name: formData.name,
        email: formData.email,
        password: formData.password,
        phone: formData.phone,
        dateOfBirth: formData.dateOfBirth,
        gender: formData.gender,
        bloodGroup: formData.bloodGroup,
        height: formData.height,
        weight: formData.weight,
        allergies: formData.allergies,
        currentMedications: formData.currentMedications,
        emergencyContact: formData.emergencyContact,
        address: formData.address,
        insuranceProvider: formData.insuranceProvider,
        insuranceId: formData.insuranceId,
        profileImage: formData.profileImage
      };

      const user = await patientSignup(completePatientData);
      console.log('Saved patient data:', user); // Debug log
      alert('Registration successful! Please login.');
      onSwitchToLogin();
    } catch (error) {
      setError(error.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  }
};
